const TOTAL = SECTIONS.length;

/* ═══════════════════════════════════════
   Easing
   ═══════════════════════════════════════ */
function easeInOutCubic(t: number): number {
  return t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;
}

/* ═══════════════════════════════════════
   Particle type
   ═══════════════════════════════════════ */
interface SectionTarget {
  x: number;
  y: number;
  isText: boolean;
}

interface Particle {
  x: number;
  y: number;
  opacity: number;
  targets: SectionTarget[];
}

/* ═══════════════════════════════════════
   Component
   ═══════════════════════════════════════ */
export default function ParticleCanvas() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const rafRef = useRef(0);
  const indicatorRef = useRef<HTMLDivElement>(null);
  const heroOverlayRef = useRef<HTMLDivElement>(null);
  const bottomBarRef = useRef<HTMLDivElement>(null);
  const navRef = useRef<HTMLElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext("2d")!;
    const dpr = Math.min(window.devicePixelRatio || 1, 2);
    const W = window.innerWidth;
    const H = window.innerHeight;

    canvas.width = W * dpr;
    canvas.height = H * dpr;
    canvas.style.width = `${W}px`;
    canvas.style.height = `${H}px`;
    ctx.scale(dpr, dpr);

    const cX = W / 2;
    const cY = H / 2;

    /* ── Grid sizing ── */
    const blockSize = W < 600 ? 3 : W < 1024 ? 3 : 4;
    const gap = 1;
    const step = blockSize + gap;
    const cols = Math.floor(W / step);
    const rows = Math.floor(H / step);
    const oX = (W - cols * step + gap) / 2;
    const oY = (H - rows * step + gap) / 2;
    const N = cols * rows;
    const halfBlock = blockSize / 2;

    /* ── Hero scale — big letters that fill the viewport ── */
    const heroScale = W < 600 ? 3 : W < 1024 ? 4 : 6;

    /* ── Pre-render circle sprite ── */
    const spriteSize = blockSize + 2;
    const dotSprite = document.createElement("canvas");
    dotSprite.width = spriteSize * dpr;
    dotSprite.height = spriteSize * dpr;
    const dctx = dotSprite.getContext("2d")!;
    dctx.scale(dpr, dpr);
    dctx.fillStyle = "#ffffff";
    dctx.beginPath();
    dctx.arc(spriteSize / 2, spriteSize / 2, halfBlock, 0, Math.PI * 2);
    dctx.fill();

    /* Enable scrolling */
    document.body.style.overflow = "auto";
    document.body.style.overflowX = "hidden";
    document.body.style.height = `${TOTAL * 100}vh`;

    /* ── Stamp pixel-art text for each section ── */
    const sectionStamps: Set<string>[] = SECTIONS.map((sec, idx) => {
      if (idx === 0) {
        /* Hero: big scaled letters */
        return stampLinesScaled(sec.lines, cols, rows, heroScale);
      }
      return stampLines(sec.lines, cols, rows, sec.lineStep);
    });

    /* ── Build targets for each section ── */
    const allTargets: SectionTarget[][] = sectionStamps.map((stamp) => {
      const targets: SectionTarget[] = [];
      for (let gy = 0; gy < rows; gy++) {
        for (let gx = 0; gx < cols; gx++) {
          targets.push({
            x: oX + gx * step + halfBlock,
            y: oY + gy * step + halfBlock,
            isText: stamp.has(`${gx},${gy}`),
          });
        }
      }
      return targets;
    });

    /* ── Create particles at center ── */
    const particles: Particle[] = [];
    /* Pre-compute per-particle entry trail data.
       Only hero-text particles get the streaming trail;
       ambient particles just fade in. */

    /* Collect indices of hero-text particles, sorted by angle from center
       so streams flow in coherent directional trails. */
    interface TrailData {
      isHeroText: boolean;
      angle: number;     /* radians from center to hero target */
      dist: number;      /* px distance center → target */
      delay: number;     /* ms before this particle starts moving */
      duration: number;  /* ms for the flight */
      ctrlX: number;     /* bezier control point */
      ctrlY: number;
    }
    const trailData: TrailData[] = [];

    /* First pass: gather all hero-text particle indices + compute angles */
    const heroTextIndices: number[] = [];
    for (let i = 0; i < N; i++) {
      const heroT = allTargets[0][i];
      if (heroT.isText) heroTextIndices.push(i);
    }

    /* Sort hero-text particles by angle (creates directional streams) then
       within similar angles, by distance (inner first → trailing outward) */
    heroTextIndices.sort((a, b) => {
      const ha = allTargets[0][a];
      const hb = allTargets[0][b];
      const angA = Math.atan2(ha.y - cY, ha.x - cX);
      const angB = Math.atan2(hb.y - cY, hb.x - cX);
      /* Quantize angle to ~24 directional bands for stream grouping */
      const bandA = Math.round(angA * 24 / (2 * Math.PI));
      const bandB = Math.round(angB * 24 / (2 * Math.PI));
      if (bandA !== bandB) return bandA - bandB;
      /* Same band: inner particles first */
      const dA = Math.hypot(ha.x - cX, ha.y - cY);
      const dB = Math.hypot(hb.x - cX, hb.y - cY);
      return dA - dB;
    });

    /* Assign sequential delay to each hero-text particle (stream stagger) */
    const TRAIL_TOTAL_DUR = 3200;  /* total animation window */
    const STAGGER_WINDOW = 2200;   /* spread spawns over this ms */
    const FLIGHT_DUR_MIN = 600;
    const FLIGHT_DUR_MAX = 1100;
    const heroTextIndexToOrder = new Map<number, number>();
    heroTextIndices.forEach((idx, order) => {
      heroTextIndexToOrder.set(idx, order);
    });
    const totalHeroText = heroTextIndices.length;

    for (let i = 0; i < N; i++) {
      const heroT = allTargets[0][i];
      const dx = heroT.x - cX;
      const dy = heroT.y - cY;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const angle = Math.atan2(dy, dx);

      const isText = heroT.isText;
      let delay = 0;
      let duration = FLIGHT_DUR_MAX;

      if (isText && heroTextIndexToOrder.has(i)) {
        /* Sequential stagger: each dot spawns slightly after previous */
        const order = heroTextIndexToOrder.get(i)!;
        delay = (order / Math.max(1, totalHeroText - 1)) * STAGGER_WINDOW;
        /* Closer = slightly faster flight */
        const normD = dist / Math.max(1, Math.hypot(W / 2, H / 2));
        duration = FLIGHT_DUR_MIN + normD * (FLIGHT_DUR_MAX - FLIGHT_DUR_MIN);
      }

      /* Curved bezier control point — perpendicular offset for arcing path */
      const perpX = -dy / (dist || 1);
      const perpY = dx / (dist || 1);
      const curveAmt = (Math.random() - 0.5) * dist * 0.35;
      const ctrlX = (cX + heroT.x) / 2 + perpX * curveAmt;
      const ctrlY = (cY + heroT.y) / 2 + perpY * curveAmt;

      trailData.push({
        isHeroText: isText,
        angle,
        dist,
        delay,
        duration,
        ctrlX,
        ctrlY,
      });

      const heroTarget = allTargets[0][i];
      const isHeroText = heroTarget.isText;

      particles.push({
        /* Hero-text particles start at center (they'll fly to target).
           Ambient particles start at their hero target position (they
           just fade in place — no expanding "paper grid" effect). */
        x: isHeroText ? cX + (Math.random() - 0.5) * 4 : heroTarget.x,
        y: isHeroText ? cY + (Math.random() - 0.5) * 4 : heroTarget.y,
        opacity: 0,
        targets: allTargets.map((st) => st[i]),
      });
    }

    /* ── Animation state ── */
    let lastScrollY = 0;
    let scrollVelocity = 0;
    let entryPhase = true;
    let entryStart = 0;
    const ENTRY_DUR = TRAIL_TOTAL_DUR;
    let time = 0;
    let currentLabel = SECTIONS[0].label;

    const dotEls =
      indicatorRef.current?.querySelectorAll<HTMLDivElement>(".pc-dot");

    /* ── RAF loop ── */
    const halfSprite = spriteSize / 2;

    const tick = (now: number) => {
      time = now * 0.001;

      const scrollY = window.scrollY;
      scrollVelocity =
        scrollVelocity * 0.85 + Math.abs(scrollY - lastScrollY) * 0.15;
      lastScrollY = scrollY;

      const progress = scrollY / H;
      const sectionA = Math.min(Math.floor(progress), TOTAL - 1);
      const sectionB = Math.min(sectionA + 1, TOTAL - 1);
      const t =
        sectionA === sectionB ? 0 : Math.min(1, progress - sectionA);
      const eased = easeInOutCubic(t);
      const activeSec = t > 0.5 ? sectionB : sectionA;

      const chaos =
        Math.sin(t * Math.PI) * Math.min(scrollVelocity * 0.4, 25);

      /* ── Is hero settled? (for static dots) ── */
      const isHeroSettled = activeSec === 0 && t < 0.01 && !entryPhase;

      /* ── Update hero overlay, bottom bar & nav visibility ── */
      /* During entry animation, keep overlays hidden. Fade them in
         smoothly once the trailing stream is nearly complete. */
      let overlayFade = 1;
      if (entryPhase && entryStart) {
        const elapsed = performance.now() - entryStart;
        /* Start fading in overlays at 70% of entry duration */
        overlayFade = Math.min(1, Math.max(0, (elapsed - ENTRY_DUR * 0.7) / (ENTRY_DUR * 0.3)));
      } else if (entryPhase) {
        overlayFade = 0;
      }
      const heroOpacity = (activeSec === 0 ? Math.max(0, 1 - t * 3) : 0) * overlayFade;
      if (heroOverlayRef.current) {
        heroOverlayRef.current.style.opacity = String(heroOpacity);
      }
      if (bottomBarRef.current) {
        bottomBarRef.current.style.opacity = String(heroOpacity);
      }
      if (navRef.current) {
        navRef.current.style.opacity = String(overlayFade);
      }
      if (indicatorRef.current) {
        indicatorRef.current.style.opacity = String(overlayFade);
      }

      /* Update section label + dots */
      const newLabel = SECTIONS[activeSec].label;
      if (newLabel !== currentLabel) {
        currentLabel = newLabel;
        if (indicatorRef.current) {
          const labelEl =
            indicatorRef.current.querySelector<HTMLDivElement>(".pc-label");
          if (labelEl) labelEl.textContent = currentLabel;
        }
        dotEls?.forEach((dot, idx) => {
          dot.classList.toggle("active", idx === activeSec);
        });
      }

      /* ── Clear ── */
      ctx.clearRect(0, 0, W, H);

      /* ── Update & draw ── */
      for (let i = 0; i < N; i++) {
        const p = particles[i];
        const fromT = p.targets[sectionA];
        const toT = p.targets[sectionB];

        let tgtX = fromT.x * (1 - eased) + toT.x * eased;
        let tgtY = fromT.y * (1 - eased) + toT.y * eased;

        /* Text blocks: bright. Ambient: very dim. */
        const opaA = fromT.isText ? 0.88 : 0.025;
        const opaB = toT.isText ? 0.88 : 0.025;
        let tgtOpacity = opaA * (1 - eased) + opaB * eased;

        /* Organic noise during transition */
        if (chaos > 0.5) {
          tgtX += Math.sin(i * 0.37 + time * 3) * chaos;
          tgtY += Math.cos(i * 0.53 + time * 3) * chaos;
        }

        /* Center pull during mid-transition */
        const centerPull = Math.sin(t * Math.PI) * 0.15;
        tgtX = tgtX * (1 - centerPull) + cX * centerPull;
        tgtY = tgtY * (1 - centerPull) + cY * centerPull;

        /* Entry animation: TRAILING STREAM
           Hero-text particles spawn sequentially with staggered delays
           and fly along curved bezier paths from center to their target,
           creating flowing streams of dots that chase each other.
           Ambient (non-text) particles simply fade in quietly. */
        if (entryPhase) {
          if (!entryStart) entryStart = now;
          const elapsed = now - entryStart;

          const td = trailData[i];

          if (td.isHeroText) {
            /* Staggered trail: each dot starts at its own delay */
            const localT = elapsed - td.delay;

            if (localT < 0) {
              /* Not spawned yet — invisible at center */
              tgtX = cX;
              tgtY = cY;
              tgtOpacity = 0;
            } else {
              const flightT = Math.min(1, localT / td.duration);

              /* easeOutCubic for smooth deceleration into position */
              const e = 1 - Math.pow(1 - flightT, 3);

              /* Quadratic bezier: center → ctrl → target */
              const u = 1 - e;
              const heroT = p.targets[0];
              const bx =
                u * u * cX + 2 * u * e * td.ctrlX + e * e * heroT.x;
              const by =
                u * u * cY + 2 * u * e * td.ctrlY + e * e * heroT.y;

              tgtX = bx;
              tgtY = by;

              /* Opacity: fade in quickly, slight trail glow during flight */
              const fadeIn = Math.min(1, localT / 150);
              /* Bright during flight, settle to final */
              const flightGlow = flightT < 0.7 ? 0.95 : 0.88;
              tgtOpacity = fadeIn * flightGlow;

              /* Scale effect: slightly larger during flight, shrink on landing */
              // (handled by the sprite — we boost opacity for glow illusion)
              if (flightT < 0.85) {
                /* Trailing tail: recent-spawned particles (the "tail") glow less */
                tgtOpacity *= 0.7 + flightT * 0.3;
              }
            }
          } else {
            /* Non-text ambient particles: stay at their target positions
               but invisible. Fade in opacity only near the end of the
               trail animation so there's no visible "paper grid" expanding
               from center. */
            const ambientFade = Math.min(
              1,
              Math.max(0, (elapsed - ENTRY_DUR * 0.65) / (ENTRY_DUR * 0.35)),
            );
            /* tgtX/tgtY stay as-is (already at correct hero target) */
            tgtOpacity *= ambientFade;
          }

          if (elapsed >= ENTRY_DUR) entryPhase = false;
        }

        /* ── Movement: static on hero, tight tracking during entry,
              organic drift elsewhere ── */
        if (entryPhase && trailData[i].isHeroText) {
          /* During trail entry: snap tightly to bezier path */
          p.x += (tgtX - p.x) * 0.45;
          p.y += (tgtY - p.y) * 0.45;
        } else if (isHeroSettled) {
          /* Fast snap to target, zero drift */
          const dx = tgtX - p.x;
          const dy = tgtY - p.y;
          if (Math.abs(dx) < 0.15 && Math.abs(dy) < 0.15) {
            p.x = tgtX;
            p.y = tgtY;
          } else {
            p.x += dx * 0.3;
            p.y += dy * 0.3;
          }
        } else {
          /* Smooth lerp + gentle organic drift */
          p.x += (tgtX - p.x) * 0.065;
          p.y += (tgtY - p.y) * 0.065;
          p.x += Math.sin(time * 0.8 + i * 0.1) * 0.08;
          p.y += Math.cos(time * 0.6 + i * 0.15) * 0.08;
        }

        p.opacity += (tgtOpacity - p.opacity) * 0.08;

        /* Draw via pre-rendered sprite */
        if (p.opacity > 0.005) {
          ctx.globalAlpha = p.opacity;
          ctx.drawImage(
            dotSprite,
            p.x - halfSprite,
            p.y - halfSprite,
            spriteSize,
            spriteSize,
          );
        }
      }

      rafRef.current = requestAnimationFrame(tick);
    };

    rafRef.current = requestAnimationFrame(tick);

    return () => {
      cancelAnimationFrame(rafRef.current);
      document.body.style.overflow = "";
      document.body.style.overflowX = "";
      document.body.style.height = "";
    };
  }, []);

  return (
    <>
      <canvas ref={canvasRef} className="pc-canvas" />

      {/* ── Navigation bar ── */}
      <nav ref={navRef} className="pc-nav" style={{ opacity: 0 }}>
        <div className="pc-nav-logo">
          KK<span className="pc-diamond">◆</span>DEV
        </div>
        <div className="pc-nav-right">
          <div className="pc-nav-links">
            <a
              href="https://github.com/kalyankumar"
              target="_blank"
              rel="noopener noreferrer"
            >
              GITHUB
            </a>
            <a
              href="https://linkedin.com/in/kalyankumar"
              target="_blank"
              rel="noopener noreferrer"
            >
              LINKEDIN
            </a>
            <a href="/resume.pdf" target="_blank" rel="noopener noreferrer">
              RESUME
            </a>
          </div>
          <a
            href="mailto:kkalyankumar.dev@gmail.com"
            className="pc-nav-email"
          >
            <span className="pc-email-dot">●</span> KKALYANKUMAR.DEV
          </a>
        </div>
      </nav>

      {/* ── Hero text overlay ── */}
      <div ref={heroOverlayRef} className="pc-hero-overlay" style={{ opacity: 0 }}>
        <p className="pc-hero-bio">
          I&apos;M KALYAN, A FULL-STACK SOFTWARE
          ENGINEER BASED IN NEW JERSEY,
          DEDICATED TO BUILDING SCALABLE
          WEB APPLICATIONS &amp; AI-POWERED
          TOOLS FOR PRODUCTION ENVIRONMENTS.
          LET&apos;S CONNECT!
        </p>
      </div>

      {/* ── Bottom bar (hero section only) ── */}
      <div ref={bottomBarRef} className="pc-bottom-bar" style={{ opacity: 0 }}>
        <span className="pc-scroll-hint">SCROLL TO SEE MORE</span>
        <span className="pc-available">AVAILABLE FOR OPPORTUNITIES</span>
      </div>

      {/* Scroll spacers */}
      <div className="pc-sections">
        {SECTIONS.map((_, i) => (
          <section key={i} className="pc-section" data-section={i} />
        ))}
      </div>

      {/* Section indicator */}
      <div ref={indicatorRef} className="pc-indicator" style={{ opacity: 0 }}>
        <div className="pc-label">{SECTIONS[0].label}</div>
        <div className="pc-dots">
          {SECTIONS.map((_, i) => (
            <div key={i} className={`pc-dot${i === 0 ? " active" : ""}`} />
          ))}
        </div>
      </div>
    </>
  );
}
